noncompliant:
// Noncompliant: Complex overloading instead of if constexpr
template<typename T>
typename std::enable_if<std::is_integral_v<T>, T>::type
process(T value) {
    return value * 2;
}

template<typename T>
typename std::enable_if<std::is_floating_point_v<T>, T>::type
process(T value) {
    return value / 2.0;
}

// Noncompliant: Multiple function template specializations
template<bool is_signed>
struct Helper {
    template<typename T>
    static T process(T value);
};

template<>
template<typename T>
T Helper<true>::process(T value) { return -value; }

template<>
template<typename T>
T Helper<false>::process(T value) { return value; }

compliant:
// Compliant: Using if constexpr for cleaner metaprogramming
template<typename T>
T process(T value) {
    if constexpr (std::is_integral_v<T>) {
        return value * 2;
    } else if constexpr (std::is_floating_point_v<T>) {
        return value / 2.0;
    }
}

// Compliant: Single function with if constexpr
template<typename T>
T helper(T value) {
    if constexpr (std::is_signed_v<T>) {
        return -value;
    } else {
        return value;
    }
}
